CREATE OR REPLACE TEMPORARY TABLE mp_dual AS SELECT CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.src_inserted_at IS NOT NULL AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.src_inserted_at) >= $1 OR demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.src_inserted_at IS NOT NULL AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.src_inserted_at) < $2) THEN CAST(date_trunc('month', demo_retail.dbo.orders.order_date) AS DATE) ELSE NULL END AS event_month, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.src_inserted_at IS NOT NULL AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.src_inserted_at) < $2) THEN $3 WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.src_inserted_at IS NOT NULL AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.src_inserted_at) >= $1 AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.src_inserted_at) > $4) THEN $5 WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.src_inserted_at IS NOT NULL AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.src_inserted_at) >= $1 AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.src_inserted_at) < $6) THEN $7 WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.src_inserted_at IS NOT NULL AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.src_inserted_at) >= $1) THEN date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.src_inserted_at) ELSE NULL END AS lag_day, CASE WHEN (demo_retail.dbo.orders.src_inserted_at IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL) THEN date_diff('day', demo_retail.dbo.orders.src_inserted_at, demo_retail.dbo.orders.loaded_at) ELSE NULL END AS delta_day, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.src_inserted_at IS NOT NULL AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.src_inserted_at) >= $1) THEN $8 ELSE $9 END AS is_source_eligible, CASE WHEN (demo_retail.dbo.orders.order_date IS NULL) THEN $10 ELSE $11 END AS is_null_event_time, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.src_inserted_at IS NULL) THEN $12 ELSE $13 END AS is_null_source_only, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.src_inserted_at IS NOT NULL AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.src_inserted_at) >= $14 AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.src_inserted_at) < $15) THEN $16 ELSE $17 END AS is_negative_clipped, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.src_inserted_at IS NOT NULL AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.src_inserted_at) < $2) THEN $18 ELSE $19 END AS is_negative_lag_excluded, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.src_inserted_at IS NOT NULL AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.src_inserted_at) >= $1 AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.src_inserted_at) > $20) THEN $21 ELSE $22 END AS is_overflow, CASE WHEN (demo_retail.dbo.orders.src_inserted_at IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL) THEN $23 ELSE $24 END AS is_delta_row, CAST(NULL AS INTEGER) AS lookup_dup 
FROM demo_retail.dbo.orders 
WHERE demo_retail.dbo.orders.loaded_at <= $25 OR demo_retail.dbo.orders.loaded_at IS NULL
